import React, { useState } from 'react';
import axios from 'axios';

function OrderForm() {
  const [service, setService] = useState('iPhone 17 Pro Max iCloud Unlock Clean/Lost');
  const [imei, setImei] = useState('');
  const [email, setEmail] = useState('');
  const [success, setSuccess] = useState(false);
  const [orderId, setOrderId] = useState('');
  const [error, setError] = useState('');

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    try {
      const res = await axios.post('http://localhost:5000/api/orders', { service, imei, email });
      setSuccess(true);
      setOrderId(res.data.order.orderId);
    } catch (err) {
      setError('وقع مشكل أثناء إرسال الطلب.');
    }
  };

  if (success) {
    return (
      <div style={{textAlign: 'center'}}>
        <h3>تم إرسال الطلب بنجاح!</h3>
        <p>رقم الطلب: <b>{orderId}</b></p>
        <p>يمكنك تتبع حالة الطلب من لوحة التتبع.</p>
      </div>
    );
  }

  return (
    <form onSubmit={handleSubmit} style={{
      maxWidth: 400,
      margin: 'auto',
      background: '#fff',
      padding: 32,
      borderRadius: 12,
      boxShadow: '0 2px 8px rgba(0,0,0,0.07)'
    }}>
      <h3 style={{
        margin: '0 0 24px 0',
        textAlign: 'center',
        color: '#1abc4c',
        fontWeight: 800,
        fontSize: 22
      }}>طلب إزالة iCloud</h3>

      <div style={{ marginBottom: 18 }}>
        <label style={{ display: 'block', marginBottom: 6, color: '#333', fontWeight: 600 }}>نوع الخدمة:</label>
        <select value={service} onChange={e => setService(e.target.value)} required style={{ width: '100%', padding: 8, borderRadius: 6, border: '1px solid #ccc' }}>
          <option value="iPhone 5S iCloud Unlock">iPhone 5S iCloud Unlock</option>
          <option value="iPhone 6 iCloud Unlock">iPhone 6 iCloud Unlock</option>
          <option value="iPhone 6 Plus iCloud Unlock">iPhone 6 Plus iCloud Unlock</option>
          <option value="iPhone 6S iCloud Unlock">iPhone 6S iCloud Unlock</option>
          <option value="iPhone 6S Plus iCloud Unlock">iPhone 6S Plus iCloud Unlock</option>
          <option value="iPhone SE iCloud Unlock">iPhone SE iCloud Unlock</option>
          <option value="iPhone 7 iCloud Unlock">iPhone 7 iCloud Unlock</option>
          <option value="iPhone 7 Plus iCloud Unlock">iPhone 7 Plus iCloud Unlock</option>
          <option value="iPhone 8 iCloud Unlock">iPhone 8 iCloud Unlock</option>
          <option value="iPhone 8 Plus iCloud Unlock">iPhone 8 Plus iCloud Unlock</option>
          <option value="iPhone X iCloud Unlock">iPhone X iCloud Unlock</option>
          <option value="iPhone XR iCloud Unlock">iPhone XR iCloud Unlock</option>
          <option value="iPhone XS iCloud Unlock">iPhone XS iCloud Unlock</option>
          <option value="iPhone XS Max iCloud Unlock">iPhone XS Max iCloud Unlock</option>
          <option value="iPhone 11 iCloud Unlock">iPhone 11 iCloud Unlock</option>
          <option value="iPhone 11 Pro iCloud Unlock">iPhone 11 Pro iCloud Unlock</option>
          <option value="iPhone 11 Pro Max iCloud Unlock">iPhone 11 Pro Max iCloud Unlock</option>
          <option value="iPhone 12 iCloud Unlock">iPhone 12 iCloud Unlock</option>
          <option value="iPhone 12 Mini iCloud Unlock">iPhone 12 Mini iCloud Unlock</option>
          <option value="iPhone 12 Pro iCloud Unlock">iPhone 12 Pro iCloud Unlock</option>
          <option value="iPhone 12 Pro Max iCloud Unlock">iPhone 12 Pro Max iCloud Unlock</option>
          <option value="iPhone 13 iCloud Unlock">iPhone 13 iCloud Unlock</option>
          <option value="iPhone 13 Mini iCloud Unlock">iPhone 13 Mini iCloud Unlock</option>
          <option value="iPhone 13 Pro iCloud Unlock">iPhone 13 Pro iCloud Unlock</option>
          <option value="iPhone 13 Pro Max iCloud Unlock">iPhone 13 Pro Max iCloud Unlock</option>
          <option value="iPhone 14 iCloud Unlock">iPhone 14 iCloud Unlock</option>
          <option value="iPhone 14 Plus iCloud Unlock">iPhone 14 Plus iCloud Unlock</option>
          <option value="iPhone 14 Pro iCloud Unlock">iPhone 14 Pro iCloud Unlock</option>
          <option value="iPhone 14 Pro Max iCloud Unlock">iPhone 14 Pro Max iCloud Unlock</option>
          <option value="iPhone 15 iCloud Unlock">iPhone 15 iCloud Unlock</option>
          <option value="iPhone 15 Plus iCloud Unlock">iPhone 15 Plus iCloud Unlock</option>
          <option value="iPhone 15 Pro iCloud Unlock">iPhone 15 Pro iCloud Unlock</option>
          <option value="iPhone 15 Pro Max iCloud Unlock">iPhone 15 Pro Max iCloud Unlock</option>
          <option value="iPhone 16 iCloud Unlock">iPhone 16 iCloud Unlock</option>
          <option value="iPhone 16 Pro iCloud Unlock">iPhone 16 Pro iCloud Unlock</option>
          <option value="iPhone 16 Pro Max iCloud Unlock">iPhone 16 Pro Max iCloud Unlock</option>
          <option value="iPhone 17 iCloud Unlock">iPhone 17 iCloud Unlock</option>
          <option value="iPhone 17 Pro iCloud Unlock">iPhone 17 Pro iCloud Unlock</option>
          <option value="iPhone 17 Pro Max iCloud Unlock Clean/Lost">iPhone 17 Pro Max iCloud Unlock Clean/Lost</option>
          <option value="iPad iCloud Unlock">iPad iCloud Unlock</option>
        </select>
      </div>

      <div style={{ marginBottom: 18 }}>
        <label style={{ display: 'block', marginBottom: 6, color: '#333', fontWeight: 600 }}>IMEI:</label>
        <input type="text" value={imei} onChange={e => setImei(e.target.value)} required maxLength={16} pattern="[A-Za-z0-9]+" style={{ width: '100%', padding: 8, borderRadius: 6, border: '1px solid #ccc' }} />
      </div>

      <div style={{ marginBottom: 24 }}>
        <label style={{ display: 'block', marginBottom: 6, color: '#333', fontWeight: 600 }}>الإيميل:</label>
        <input type="email" value={email} onChange={e => setEmail(e.target.value)} required style={{ width: '100%', padding: 8, borderRadius: 6, border: '1px solid #ccc' }} />
      </div>

      <button type="submit" style={{
        width: '100%',
        background: '#1abc4c',
        color: '#fff',
        border: 'none',
        padding: 12,
        borderRadius: 6,
        fontSize: 17,
        fontWeight: 700,
        letterSpacing: 1,
        cursor: 'pointer',
        transition: 'background 0.2s'
      }}>إرسال الطلب</button>
      {error && <p style={{color: 'red', marginTop: 12}}>{error}</p>}
    </form>
  );
}

export default OrderForm;
